class Solution:
    def countSquares(self, matrix):
        # Brute force: for each cell, try all square sizes and count valid ones.
        m, n = len(matrix), len(matrix[0])
        count = 0
        for r in range(m):
            for c in range(n):
                # Try squares of increasing side with top-left at (r, c)
                s = 1
                while r + s <= m and c + s <= n:
                    # Check if this s x s sub-matrix is all ones
                    ok = True
                    for dr in range(s):
                        for dc in range(s):
                            if matrix[r + dr][c + dc] == 0:
                                ok = False
                                break
                        if not ok:
                            break
                    if ok:
                        count += 1
                    else:
                        break
                    s += 1
        return count

